// Package bead implements the on-disk bead tracker.
//
// Size envelope (ddx-f8a11202):
//
// Individual bead fields — description, acceptance, notes, and each event's
// body — are bounded by MaxFieldBytes (65,535 bytes). This matches upstream
// bd's Dolt TEXT column limit so DDx-authored beads can always round-trip
// through `bd import`. Writers exceeding the cap are truncated with a
// `…[truncated, N bytes]` marker at AppendEvent; callers that need to
// preserve the full payload (notably reviewer streams) should persist to a
// sidecar artifact under `.ddx/executions/<id>/` and record a path
// reference in the event body.
//
// On the read side, scanners use a 16MB buffer — real-world incidents have
// produced 1.46MB bead rows and ~7MB session-log rows when writers bypassed
// the cap. 16MB comfortably fits a bead with dozens of maxed-out fields and
// matches the scanner in the agent package.
package bead

import (
	"bufio"
	"bytes"
	"context"
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
)

// Store manages beads via a pluggable backend.
type Store struct {
	Collection string
	Dir        string
	File       string
	Prefix     string
	LockDir    string
	LockWait   time.Duration
	backend    RawBackend // nil means use built-in JSONL
}

// Compile-time check: *Store satisfies the high-level Backend interface
// declared in backend.go. This is the contract chaos_test.go and (eventually)
// cli/cmd callers program against.
var _ Backend = (*Store)(nil)

type StoreOption func(*Store)

// WithCollection selects the logical bead collection. The default collection
// remains "beads", which maps to "beads.jsonl" in the JSONL backend.
func WithCollection(name string) StoreOption {
	return func(s *Store) {
		if cleaned := normalizeCollection(name); cleaned != "" {
			s.Collection = cleaned
		}
	}
}

// NewStore creates a store with the given directory.
// Defaults can be overridden via options or environment.
func NewStore(dir string, opts ...StoreOption) *Store {
	if dir == "" {
		dir = envOr("DDX_BEAD_DIR", ".ddx")
	}
	workingDir := dir
	if filepath.Base(dir) == ".ddx" {
		workingDir = filepath.Dir(dir)
	}
	prefix := envOr("DDX_BEAD_PREFIX", "")
	var configBackend string
	if cfg, err := config.LoadWithWorkingDir(workingDir); err == nil && cfg != nil && cfg.Bead != nil {
		if prefix == "" && cfg.Bead.IDPrefix != "" {
			prefix = cfg.Bead.IDPrefix
		}
		configBackend = cfg.Bead.Backend
	}
	if prefix == "" {
		prefix = detectPrefix(workingDir)
	}
	// Backend selection: env var wins, then config, then jsonl default.
	backendType := os.Getenv("DDX_BEAD_BACKEND")
	if backendType == "" {
		backendType = configBackend
	}
	if backendType == "" {
		backendType = BackendJSONL
	}

	s := &Store{
		Collection: DefaultCollection,
		Dir:        dir,
		Prefix:     prefix,
		LockWait:   parseDurationOr("DDX_BEAD_LOCK_TIMEOUT", 10*time.Second),
	}
	for _, opt := range opts {
		if opt != nil {
			opt(s)
		}
	}
	spec := DefaultRegistry().Resolve(CollectionID(s.Collection))
	s.File, s.LockDir = spec.PathsUnder(dir)

	// Set up external backend if configured. bd/br lack per-collection
	// scoping in their CLI, so non-default collections (e.g. beads-archive)
	// route through a JSONL fallback the external backend transparently
	// delegates to. The default collection always goes straight to bd/br
	// to preserve the existing interchange contract (schema_compat_test.go,
	// import/export round-trip).
	switch backendType {
	case BackendBD, BackendBR:
		var fallback RawBackend
		if s.Collection != DefaultCollection {
			fallback = NewJSONLBackend(s.Dir, s.File, s.LockDir, s.LockWait)
		}
		if ext, err := NewExternalBackendWithFallback(backendType, s.Collection, fallback); err == nil {
			s.backend = ext
		}
		// Fall through to JSONL if tool not available
	case BackendAxon:
		// Per ddx-95ec5ed5 AC §3 the axon backend ships behind a feature
		// flag until ddx-743bc194 (chaos conformance) signs off. Routing
		// only happens when DDX_AXON_EXPERIMENTAL is truthy; otherwise we
		// warn once and fall through to JSONL so the workspace stays
		// usable on misconfiguration.
		if AxonExperimentalEnabled() {
			s.backend = NewAxonBackend(s.Dir, s.LockWait)
		} else {
			fmt.Fprintf(os.Stderr, "bead: backend=axon ignored: set %s=1 to opt in (axon backend is experimental)\n", AxonExperimentalEnv)
		}
	}

	return s
}

// NewStoreWithCollection creates a store for a named logical collection.
func NewStoreWithCollection(dir, collection string) *Store {
	return NewStore(dir, WithCollection(collection))
}

// Init creates the storage directory and file.
func (s *Store) Init() error {
	if s.backend != nil {
		return s.backend.Init()
	}
	if err := os.MkdirAll(s.Dir, 0o755); err != nil {
		return fmt.Errorf("bead: init dir: %w", err)
	}
	f, err := os.OpenFile(s.File, os.O_CREATE|os.O_WRONLY, 0o644)
	if err != nil {
		return fmt.Errorf("bead: init file: %w", err)
	}
	return f.Close()
}

// GenID generates a unique bead ID with the configured prefix.
func (s *Store) GenID() (string, error) {
	b := make([]byte, 4)
	if _, err := rand.Read(b); err != nil {
		return "", fmt.Errorf("bead: gen id: %w", err)
	}
	return fmt.Sprintf("%s-%s", s.Prefix, hex.EncodeToString(b)), nil
}

// ReadAll loads all beads from the configured backend.
func (s *Store) ReadAll() ([]Bead, error) {
	return s.ReadAllFiltered(nil)
}

// ReadAllFiltered loads all beads, folds them by latest-wins, and returns only
// those for which the predicate returns true. When the predicate is nil every
// bead is returned (equivalent to ReadAll). The predicate is applied at the
// per-entry parse boundary after fold — matched beads are appended directly to
// the return slice without first being held in an intermediate full-corpus
// list, so queries that match a small subset avoid materializing the
// mismatches (ddx-9ce6842a Part 2 step 2: filter pushdown).
func (s *Store) ReadAllFiltered(pred func(Bead) bool) ([]Bead, error) {
	if s.backend != nil {
		all, err := s.backend.ReadAll()
		if err != nil {
			return nil, err
		}
		if pred == nil {
			return all, nil
		}
		out := make([]Bead, 0, len(all))
		for _, b := range all {
			if pred(b) {
				out = append(out, b)
			}
		}
		return out, nil
	}
	beads, warnings, err := s.readAllRaw()
	if err != nil {
		return nil, fmt.Errorf("bead: read %s: %w", s.File, err)
	}
	beads = foldLatestBeads(beads)
	for _, warning := range warnings {
		fmt.Fprintln(os.Stderr, warning)
	}
	if len(warnings) > 0 && len(beads) > 0 {
		repaired, repairErr := s.repairJSONL()
		if repairErr != nil {
			return beads, fmt.Errorf("bead: repair %s: %w", s.File, repairErr)
		}
		if repaired {
			fmt.Fprintf(os.Stderr, "bead: repaired %s; backup written to %s.bak\n", s.File, s.File)
		}
	}
	if len(beads) == 0 && len(warnings) > 0 {
		return nil, fmt.Errorf("bead: read %s: %d malformed record(s), 0 valid", s.File, len(warnings))
	}
	if pred == nil {
		return beads, nil
	}
	out := make([]Bead, 0, len(beads))
	for _, b := range beads {
		if pred(b) {
			out = append(out, b)
		}
	}
	return out, nil
}

func (s *Store) readAllRaw() ([]Bead, []string, error) {
	data, err := os.ReadFile(s.File)
	if os.IsNotExist(err) {
		return nil, nil, nil
	}
	if err != nil {
		return nil, nil, fmt.Errorf("read: %w", err)
	}
	beads, warnings, err := parseBeadJSONL(data)
	if err != nil {
		return nil, nil, err
	}
	return beads, warnings, nil
}

func parseBeadJSONL(data []byte) ([]Bead, []string, error) {
	scanner := bufio.NewScanner(bytes.NewReader(data))
	// 16MB max line. Real-world extremes observed: 1.46MB bead rows when a
	// reviewer stream dumped into events[].body, and bd-exported lines stacking
	// many 65KB fields. bd's upstream per-field cap is 65,535 bytes; an
	// individual bead with dozens of maxed-out fields fits comfortably in 16MB.
	scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)

	var beads []Bead
	var warnings []string
	lineNo := 0
	for scanner.Scan() {
		lineNo++

	} else if lintThreshold > 0 && lintResult.Score < lintThreshold {
		blockMsg := fmt.Sprintf(
			"pre-dispatch lint blocked dispatch for %s: score=%d below threshold=%d; see bead-lifecycle MODE: lint guidance in .agents/skills/ddx/bead-lifecycle/SKILL.md",
			candidate.ID, lintResult.Score, lintThreshold,
		)
		if runtime.Log != nil {
			_, _ = fmt.Fprintln(runtime.Log, blockMsg)
		}
		emit("pre_dispatch_lint.blocked", map[string]any{
			"bead_id":          candidate.ID,
			"score":            lintResult.Score,
			"threshold_score":  lintThreshold,
			"skill":            "bead-lifecycle",
			"skill_path":       ".agents/skills/ddx/bead-lifecycle/SKILL.md",
			"dispatch_skipped": true,
			"warning_mode":     false,
			"rationale":        lintResult.Rationale,
			"suggested_fixes":  lintResult.SuggestedFixes,
			"waivers_applied":  lintResult.WaiversApplied,
		})
		if runtime.Once {
			exitReason = "once_complete"
			return result, nil
		}
		continue
	}
}

if err := w.Store.Claim(candidate.ID, assignee); err != nil {
	// Another worker won the race for this bead. Emit a structured
	// claim_race event so concurrent-worker losses are observable
	// (ddx-9d55601f AC #4). The bead remains in `attempted` for this
	// run; on the next iteration it will be filtered out of
	// ReadyExecution naturally because Claim() flipped it to
	// in_progress, so the loser keeps moving down priority order.
	emit("picker.claim_race", map[string]any{
		"bead_id":  candidate.ID,
		"priority": candidate.Priority,
		"reason":   err.Error(),
	})
	continue
}

emit("bead.claimed", map[string]any{
	"bead_id":  candidate.ID,
	"title":    candidate.Title,
	"assignee": assignee,
})

if runtime.Log != nil {
	if candidate.Title != "" {
		_, _ = fmt.Fprintf(runtime.Log, "\n▶ %s: %s\n", candidate.ID, candidate.Title)
	} else {
		_, _ = fmt.Fprintf(runtime.Log, "\n▶ %s\n", candidate.ID)
	}
}

// Generate a provisional attempt_id for progress events.
// The real attempt_id is assigned inside ExecuteBead; we use this
// for queueing/running events and replace with the real one once known.
provAttemptID := time.Now().UTC().Format("20060102T150405") + "-" + randomProgressID()
runStart := now()
phaseSeq := 0
nextPhase := func(phase string, heartbeat bool) {
	phaseSeq++
	emitProgress(runtime.ProgressCh, newProgressEvent(
		runtime.WorkerID, runtime.ProjectRoot, candidate.ID, provAttemptID,
		harness, model, profile,
		phase, phaseSeq, heartbeat, now().Sub(runStart).Milliseconds(),
	))
}

nextPhase("queueing", false)

hbCtx, hbCancel := context.WithCancel(ctx)
var hbWG sync.WaitGroup
hbWG.Add(1)
go func(beadID string) {
	defer hbWG.Done()
	ticker := time.NewTicker(heartbeatInterval)
	defer ticker.Stop()
	for {
		select {
		case <-hbCtx.Done():
			return
		case <-ticker.C:
			_ = w.Store.Heartbeat(beadID)
		}
	}
}(candidate.ID)

nextPhase("running", false)

// tryExecutor preserves the legacy w.Executor.Execute(ctx, candidate.ID)
// invocation while letting try.Attempt own conflict recovery.
attemptOut, err := agenttry.Attempt(ctx, w.Store, candidate.ID, agenttry.AttemptOpts{
	Bead:                candidate,
	Executor:            tryExecutor(w.Executor),
	Store:               w.Store,
	ProjectRoot:         runtime.ProjectRoot,
	SatisfactionChecker: w.SatisfactionChecker,
	VerificationRunner:  w.VerificationRunner,
	AutoRecover:         tryAutoRecover(w.conflictAutoRecoverFn),
	ConflictResolver:    w.ConflictResolver,
	Assignee:            assignee,
	Now:                 now,
	Cooldown:            LandConflictCooldown,
})
hbCancel()
hbWG.Wait()
report := fromTryReport(attemptOut.Report)
if report.BeadID == "" {
	report.BeadID = candidate.ID
}
if report.Status == "" {
	report.Status = ExecuteBeadStatusExecutionFailed
}
if report.Detail == "" {
	report.Detail = ExecuteBeadStatusDetail(report.Status, "", "")
}
// ddx-5b3e57f4: distinguish worker-disrupted from model-gave-up.
// A failed attempt where the loop ctx was cancelled, or the executor
// surfaced a transport-class error, is not evidence the model could
// not make progress — skip the no-progress cooldown so the bead is
// immediately re-claimable. If the executor itself already marked
// report.Disrupted (e.g. a future SIGKILL/SIGTERM or server-restart
// classifier inside ExecuteBeadWithConfig), preserve it.
if !report.Disrupted && report.Status != ExecuteBeadStatusSuccess {
	if reason, disrupted := classifyDisruption(ctx, err); disrupted {
		report.Disrupted = true
		report.DisruptionReason = reason
	}
}
if report.Disrupted {
	reason := report.DisruptionReason
	if reason == "" {
		reason = "unknown"
	}
	emitDisruptionDetected(emit, w.Store, candidate.ID,
		reason, report.Detail, report.Harness, report.Model, assignee, now().UTC())
}

result.Attempts++

if attemptOut.StoreErr != nil {
	_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
		return commitOutcomeError(attemptOut.StoreErrOp, assignee, result, attemptOut.StoreErr)
	})
}

if parking := attemptOut.Parking; parking != nil {
	if parking.Unclaim {
		if err := w.Store.Unclaim(candidate.ID); err != nil {
			_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
				return commitOutcomeError("Unclaim", assignee, result, err)
			})
			if ctx.Err() != nil {
				return result, ctx.Err()
			}
			continue
		}

package bead

import (
	"bufio"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"sync"
	"sync/atomic"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestMain scrubs all GIT_* environment variables before running tests so
// test subprocesses don't inherit lefthook's GIT_DIR/GIT_WORK_TREE and leak
// into the parent repo's config.
func TestMain(m *testing.M) {
	for _, kv := range os.Environ() {
		if strings.HasPrefix(kv, "GIT_") {
			if idx := strings.IndexByte(kv, '='); idx >= 0 {
				_ = os.Unsetenv(kv[:idx])
			}
		}
	}
	os.Exit(m.Run())
}

func newTestStore(t *testing.T) *Store {
	t.Helper()
	dir := t.TempDir()
	s := NewStore(filepath.Join(dir, ".ddx"))
	require.NoError(t, s.Init())
	return s
}

func TestInit(t *testing.T) {
	dir := t.TempDir()
	s := NewStore(filepath.Join(dir, ".ddx"))
	require.NoError(t, s.Init())

	_, err := os.Stat(s.File)
	assert.NoError(t, err, "beads.jsonl should exist after init")
}

func TestInitUsesCollectionFile(t *testing.T) {
	dir := t.TempDir()
	s := NewStoreWithCollection(filepath.Join(dir, ".ddx"), "exec-runs")
	require.Equal(t, "exec-runs", s.Collection)
	require.Equal(t, filepath.Join(dir, ".ddx", "exec-runs.jsonl"), s.File)
	require.Equal(t, filepath.Join(dir, ".ddx", "exec-runs.lock"), s.LockDir)
	require.NoError(t, s.Init())

	_, err := os.Stat(s.File)
	assert.NoError(t, err, "collection file should exist after init")
}

func TestWithCollectionNormalizesJSONLExtension(t *testing.T) {
	dir := t.TempDir()
	s := NewStore(filepath.Join(dir, ".ddx"), WithCollection("agent-sessions.jsonl"))
	assert.Equal(t, "agent-sessions", s.Collection)
	assert.Equal(t, filepath.Join(dir, ".ddx", "agent-sessions.jsonl"), s.File)
}

func TestExternalBackendCarriesLogicalCollectionName(t *testing.T) {
	toolDir := t.TempDir()
	writeFakeBackendTool(t, toolDir, "bd")
	writeFakeBackendTool(t, toolDir, "br")
	t.Setenv("PATH", toolDir+string(os.PathListSeparator)+os.Getenv("PATH"))

	for _, tc := range []struct {
		name       string
		backend    string
		collection string
	}{
		{name: "default-bd", backend: "bd", collection: DefaultCollection},
		{name: "exec-runs-bd", backend: "bd", collection: "exec-runs"},
		{name: "agent-sessions-br", backend: "br", collection: "agent-sessions"},
	} {
		t.Run(tc.name, func(t *testing.T) {
			t.Setenv("DDX_BEAD_BACKEND", tc.backend)
			s := NewStore(filepath.Join(t.TempDir(), ".ddx"), WithCollection(tc.collection))
			backend, ok := s.backend.(*ExternalBackend)
			require.True(t, ok)
			assert.Equal(t, tc.backend, backend.Tool)
			assert.Equal(t, tc.collection, backend.Collection)
		})
	}
}

func TestExternalBackendFallsBackWhenToolMissing(t *testing.T) {
	t.Setenv("PATH", "")
	t.Setenv("DDX_BEAD_BACKEND", "bd")

	s := NewStore(filepath.Join(t.TempDir(), ".ddx"), WithCollection("exec-runs"))
	assert.Nil(t, s.backend)
}

// TestExternalBackendOpensBeadsArchiveWithFallback verifies that opening the
// "beads-archive" collection through the bd external backend produces a
// working read/write path via the JSONL fallback, without invoking bd.
// bd/br do not yet expose per-collection scoping in their CLI surface, so
// non-default collections must round-trip through .ddx/<collection>.jsonl
// to avoid colliding with the tool's primary store.
func TestExternalBackendOpensBeadsArchiveWithFallback(t *testing.T) {
	toolDir := t.TempDir()
	// A fake bd that always errors. If the backend ever shells out for the
	// archive collection, ReadAll/WriteAll will fail and this test will
	// catch the regression.
	failScript := "#!/bin/sh\necho 'fake bd should not be called for non-default collections' 1>&2\nexit 1\n"
	failBd := filepath.Join(toolDir, "bd")
	require.NoError(t, os.WriteFile(failBd, []byte(failScript), 0o755))
	t.Setenv("PATH", toolDir+string(os.PathListSeparator)+os.Getenv("PATH"))
	t.Setenv("DDX_BEAD_BACKEND", "bd")

	dir := t.TempDir()
	ddxDir := filepath.Join(dir, ".ddx")
	s := NewStore(ddxDir, WithCollection(BeadsArchiveCollection))

	backend, ok := s.backend.(*ExternalBackend)
	require.True(t, ok, "expected ExternalBackend for bd + non-default collection")
	require.Equal(t, "bd", backend.Tool)
	require.Equal(t, BeadsArchiveCollection, backend.Collection)
	require.NotNil(t, backend.fallback, "non-default collection must have JSONL fallback")

	// Init must not panic and must create the archive file under .ddx/.
	require.NoError(t, s.Init())
	archivePath := filepath.Join(ddxDir, BeadsArchiveCollection+".jsonl")
	_, err := os.Stat(archivePath)
	require.NoError(t, err, "archive file should exist after Init")

	// Empty read works.
	got, err := s.ReadAll()
	require.NoError(t, err)
	assert.Empty(t, got)

	// Round-trip a bead through WriteAll/ReadAll without touching bd.
	want := Bead{ID: "ddx-arch-1", Title: "archived item", Status: StatusClosed, IssueType: "task", Priority: 2}
	require.NoError(t, s.WriteAll([]Bead{want}))
	got, err = s.ReadAll()
	require.NoError(t, err)
	require.Len(t, got, 1)
	assert.Equal(t, want.ID, got[0].ID)
	assert.Equal(t, want.Title, got[0].Title)
}

// TestExternalBackendDefaultCollectionHasNoFallback locks in that the
// default "beads" collection still routes directly to bd/br so the existing
// interchange contract (schema_compat_test.go, import/export round-trip)
// stays unchanged.
func TestExternalBackendDefaultCollectionHasNoFallback(t *testing.T) {
	toolDir := t.TempDir()
	writeFakeBackendTool(t, toolDir, "bd")
	t.Setenv("PATH", toolDir+string(os.PathListSeparator)+os.Getenv("PATH"))
	t.Setenv("DDX_BEAD_BACKEND", "bd")

	s := NewStore(filepath.Join(t.TempDir(), ".ddx"))
	backend, ok := s.backend.(*ExternalBackend)
	require.True(t, ok)
	assert.Equal(t, DefaultCollection, backend.Collection)
	assert.Nil(t, backend.fallback, "default collection must not use fallback")
}

func writeFakeBackendTool(t *testing.T, dir, name string) {
	t.Helper()
	path := filepath.Join(dir, name)
	script := "#!/bin/sh\nexit 0\n"
	require.NoError(t, os.WriteFile(path, []byte(script), 0o755))
}

func TestCreateAndGet(t *testing.T) {
	s := newTestStore(t)

	b := &Bead{Title: "Fix auth bug", IssueType: "bug", Priority: 1}
	require.NoError(t, s.Create(b))

	assert.NotEmpty(t, b.ID)
	assert.True(t, len(b.ID) > 3, "ID should have prefix + hex")
	assert.Equal(t, "bug", b.IssueType)
	assert.Equal(t, StatusOpen, b.Status)
	assert.Equal(t, 1, b.Priority)
	assert.False(t, b.CreatedAt.IsZero())

	got, err := s.Get(b.ID)
	require.NoError(t, err)
	assert.Equal(t, b.Title, got.Title)
	assert.Equal(t, b.IssueType, got.IssueType)
}

func TestCreateUsesConfiguredPrefix(t *testing.T) {
	t.Setenv("DDX_BEAD_PREFIX", "")
	tempDir := t.TempDir()
	ddxDir := filepath.Join(tempDir, ".ddx")
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(ddxDir, "config.yaml"), []byte(`version: "1.0"
library:
  path: "./library"
  repository:
    url: "https://github.com/test/repo"
    branch: "main"
bead:
  id_prefix: "nif"
`), 0o644))

	s := NewStore(filepath.Join(tempDir, ".ddx"))
	require.NoError(t, s.Init())

	b := &Bead{Title: "Configured prefix"}
	require.NoError(t, s.Create(b))

	assert.True(t, strings.HasPrefix(b.ID, "nif-"))
}

func TestCreateUsesEnvPrefixOverConfig(t *testing.T) {
	tempDir := t.TempDir()
	ddxDir := filepath.Join(tempDir, ".ddx")
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(ddxDir, "config.yaml"), []byte(`version: "1.0"
library:
  path: "./library"
  repository:
    url: "https://github.com/test/repo"
    branch: "main"
bead:
  id_prefix: "nif"
`), 0o644))

	t.Setenv("DDX_BEAD_PREFIX", "env")

	s := NewStore(filepath.Join(tempDir, ".ddx"))
	require.NoError(t, s.Init())

	b := &Bead{Title: "Env prefix"}
	require.NoError(t, s.Create(b))

	assert.True(t, strings.HasPrefix(b.ID, "env-"))
}

func TestCreateDefaults(t *testing.T) {
	s := newTestStore(t)

	b := &Bead{Title: "Simple task"}
	require.NoError(t, s.Create(b))

	assert.Equal(t, DefaultType, b.IssueType)
	assert.Equal(t, DefaultStatus, b.Status)
