// matchesWhere returns true if the bead satisfies all key=value predicates.
// It checks known struct fields first, then falls back to Extra.
func matchesWhere(b Bead, where map[string]string) bool {
	for k, v := range where {
		var actual string
		switch k {
		case "id":
			actual = b.ID
		case "title":
			actual = b.Title
		case "status":
			actual = b.Status
		case "issue_type":
			actual = b.IssueType
		case "owner":
			actual = b.Owner
		case "assignee":
			actual = b.Owner
		case "parent":
			actual = b.Parent
		case "description":
			actual = b.Description
		case "acceptance":
			actual = b.Acceptance
		case "notes":
			actual = b.Notes
		default:
			// Fall back to Extra map for unknown/workflow-specific fields
			if b.Extra != nil {
				if ev, ok := b.Extra[k]; ok {
					actual = fmt.Sprintf("%v", ev)
				}
			}
		}
		if actual != v {
			return false
		}
	}
	return true
}

