// ---------------------------------------------------------------------------
// Executor helpers
// ---------------------------------------------------------------------------

// landSerializerMu guards landSerializerMap.
var (
	landSerializerMu  sync.Mutex
	landSerializerMap = map[string]*sync.Mutex{}
)

// landMutexFor returns the per-projectRoot mutex that serializes Land() calls.
// This mimics the production per-project LandCoordinator goroutine
// (cli/internal/server/workers.go). Tests that spawn concurrent workers share
// this mutex so the CAS-based UpdateRefTo in Land() never races.
func landMutexFor(projectRoot string) *sync.Mutex {
	landSerializerMu.Lock()
	defer landSerializerMu.Unlock()
	m, ok := landSerializerMap[projectRoot]
	if !ok {
		m = &sync.Mutex{}
		landSerializerMap[projectRoot] = m
	}
	return m
}

// scriptHarnessExecutor builds an ExecuteBeadExecutorFunc that:
//  1. Runs ExecuteBead with the script harness (directive file = directivePath).
//  2. Passes the result through LandBeadResult with a LandingAdvancer that
//     calls Land() — serialized via landMutexFor(projectRoot).
//
// Both ExecuteBead and Land() are serialized per projectRoot. This is required
// because ExecuteBead calls CommitTracker (which acquires the git index lock)
// and because Land() uses CAS-based UpdateRefTo. In production, the server
// dispatches one bead per worker and serializes Land() via the LandCoordinator
// goroutine; in integration tests, the same mutex handles both.
//
// Failed exits (exit code != 0) with commits are preserved under
// refs/ddx/iterations/ by LandBeadResult before Land() is invoked.
func scriptHarnessExecutor(t *testing.T, projectRoot, directivePath string) ExecuteBeadExecutorFunc {
	t.Helper()
	// Build Runner once at executor-construction time so concurrent goroutine
	// calls do not race on BuiltinCatalog (NewRunner is not goroutine-safe
	// during catalog construction).
	runner := NewRunner(Config{})
	gitOps := &RealGitOps{}
	orchGitOps := &RealOrchestratorGitOps{}
	// Per-projectRoot mutex serializes git operations so concurrent workers
	// don't race on the git index or on Land()'s CAS UpdateRefTo.
	repoMu := landMutexFor(projectRoot)

	cfg := config.NewTestConfigForBead(config.TestBeadConfigOpts{
		Harness: "script",
		Model:   directivePath,
	})
	rcfg := cfg.Resolve(config.CLIOverrides{})

	return ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
		repoMu.Lock()
		defer repoMu.Unlock()

		res, err := ExecuteBeadWithConfig(ctx, projectRoot, beadID, rcfg, ExecuteBeadRuntime{
			AgentRunner: runner,
		}, gitOps)
		if err != nil {
			if res != nil {
				return executeBeadResultToReport(res), nil
			}
			return ExecuteBeadReport{
				BeadID: beadID,
				Status: ExecuteBeadStatusExecutionFailed,
				Detail: err.Error(),
			}, nil
		}

		landing, landErr := LandBeadResult(projectRoot, res, orchGitOps, BeadLandingOptions{
			LandingAdvancer: func(r *ExecuteBeadResult) (*LandResult, error) {
				// landMutexFor is already held (repoMu == landMutexFor(projectRoot)).
				req := BuildLandRequestFromResult(projectRoot, r)
				return Land(projectRoot, req, RealLandingGitOps{})
			},
		})
		if landErr != nil {
			return ExecuteBeadReport{
				BeadID: beadID,
				Status: ExecuteBeadStatusExecutionFailed,
				Detail: landErr.Error(),
			}, nil
		}
		ApplyLandingToResult(res, landing)
		return executeBeadResultToReport(res), nil
	})
}

// executeBeadResultToReport converts ExecuteBeadResult to ExecuteBeadReport.
func executeBeadResultToReport(res *ExecuteBeadResult) ExecuteBeadReport {
	return ExecuteBeadReport{
		BeadID:             res.BeadID,
		AttemptID:          res.AttemptID,

		res.Status = ExecuteBeadStatusNoEvidenceProduced
	default:
		res.Status = ExecuteBeadStatusExecutionFailed
	}
	res.Detail = ExecuteBeadStatusDetail(res.Status, "", res.Error)
}

// CommitTracker commits beads.jsonl if it has uncommitted changes.
func CommitTracker(projectRoot string) error {
	trackerFile := filepath.Join(projectRoot, ".ddx", "beads.jsonl")
	info, err := os.Stat(trackerFile)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return fmt.Errorf("checking tracker file: %w", err)
	}
	if info.IsDir() {
		return nil
	}

	out, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Output()
	if err != nil || strings.TrimSpace(string(out)) != "true" {
		return nil
	}

	msg := fmt.Sprintf("chore: update tracker (execute-bead %s)", time.Now().UTC().Format("20060102T150405"))
	// Serialize git add/commit on the primary .git across processes so that
	// concurrent workers (multiple `ddx work`) do not race on
	// .git/index.lock. See cli/internal/agent/tracker_lock.go.
	return withTrackerLock(projectRoot, func() error {
		// Re-check inside the lock: a sibling worker may have already
		// committed the tracker changes between our pre-lock check and now.
		diff, err := internalgit.Command(context.Background(), projectRoot, "diff", "--", ".ddx/beads.jsonl").Output()
		if err != nil {
			return fmt.Errorf("checking tracker diff: %w", err)
		}
		if strings.TrimSpace(string(diff)) == "" {
			untracked, err := internalgit.Command(context.Background(), projectRoot, "ls-files", "--others", "--exclude-standard", ".ddx/beads.jsonl").Output()
			if err != nil {
				return fmt.Errorf("checking tracker untracked: %w", err)
			}
			if strings.TrimSpace(string(untracked)) == "" {
				return nil
			}
		}

		}

		commitOut, err := internalgit.Command(context.Background(), projectRoot, "add", ".ddx/beads.jsonl").CombinedOutput()
		if err != nil {
			return fmt.Errorf("staging tracker: %s: %w", strings.TrimSpace(string(commitOut)), err)
		}
		// `git commit` would fail with "nothing to commit" if the file's
		// content is byte-identical to HEAD even though `git diff` saw a
		// diff (e.g. mode/whitespace race). Bail cleanly in that case.
		if cached, err := internalgit.Command(context.Background(), projectRoot, "diff", "--cached", "--", ".ddx/beads.jsonl").Output(); err == nil && strings.TrimSpace(string(cached)) == "" {
			return nil
		}
		commitOut, err = internalgit.Command(context.Background(), projectRoot, "commit", "--no-verify", "-m", msg).CombinedOutput()
		if err != nil {
			return fmt.Errorf("committing tracker: %s: %w", strings.TrimSpace(string(commitOut)), err)
		}
		return nil
	})
}

func resolveBase(gitOps GitOps, workDir, fromRev string) (string, error) {
	if fromRev == "" || fromRev == "HEAD" {
		rev, err := gitOps.HeadRev(workDir)
		if err != nil {
			return "", fmt.Errorf("resolving HEAD: %w", err)
		}
		return rev, nil
	}
	rev, err := gitOps.ResolveRev(workDir, fromRev)
	if err != nil {
		return "", fmt.Errorf("resolving --from %q: %w", fromRev, err)
	}
	return rev, nil
}

